class efuAI {
    constructor() {
        this.root = "https://summary.tianli0.top";
        this.aiTalkMode = false;
        this.aiPostExplanation = '';
        this.config = GLOBAL_CONFIG.post_ai;
        this.scoGPTIsRunning = false;
    }

    init() {
        const aiExplanationElement = document.querySelector(".ai-explanation");
        if (!aiExplanationElement) return;

        this.scoGPTIsRunning = false;
        this.aiPostExplanation = PAGE_CONFIG.ai_text ? PAGE_CONFIG.ai_text + '' : false;

        if (!this.aiPostExplanation) {
            this.generate();
        } else {
            this.aiShowAnimation(Promise.resolve(this.aiPostExplanation));
        }

        this.AIEngine();
    }

    getTitleAndContent() {
        const articleContainer = document.getElementById("article-container");
        const title = document.title;
        const paragraphs = Array.from(articleContainer.getElementsByTagName("p"));
        const headings = Array.from(articleContainer.querySelectorAll("h1, h2, h3, h4, h5"));

        const content = (title + ' ' + (headings.concat(paragraphs)).map((element) => element.innerText.replace(/https?:\/\/[^\s]+/g, '')).join(' ')).slice(0, 1000);
        return content;
    }

    async generate() {
        this.aiShowAnimation(this.fetch(document.title, this.getTitleAndContent(), this.config.key));
    }

    async fetch(title, content, apiKey) {
        const url = `${this.root}/?content=${encodeURIComponent(content)}&title=${encodeURIComponent(title)}&key=${encodeURIComponent(apiKey)}&url=${encodeURIComponent(window.location.href)}`;
        try {
            const response = await fetch(url);
            const data = await response.json();
            if (response.ok) {
                this.aiPostExplanation = data.summary;
                return data.summary;
            } else {
                console.error("Request failed:", data.err_msg);
                return data.err_msg;
            }
        } catch (error) {
            console.error("Network request failed:", error);
            return "Network request failed";
        }
    }

    aiShowAnimation(promise, showSuggestions = false) {
        const aiExplanationElement = document.querySelector(".ai-explanation");
        const aiTagElement = document.querySelector(".ai-tag");

        if (!aiExplanationElement || this.scoGPTIsRunning) return;

        this.scoGPTIsRunning = true;
        this.cleanSuggestions();
        aiTagElement.classList.add("loadingAI");
        aiExplanationElement.style.display = "block";
        aiExplanationElement.innerHTML = '生成中...<span class="blinking-cursor"></span>';

        let currentText = '';
        let currentIndex = 0;
        let isIntersecting = false;
        let animationFrameId = null;

        const observer = new IntersectionObserver((entries) => {
            isIntersecting = entries[0].isIntersecting;
            if (isIntersecting) {
                animationFrameId = requestAnimationFrame(render);
            }
        }, { threshold: 0 });

        observer.observe(aiExplanationElement);

        promise.then((text) => {
            const render = () => {
                if (currentIndex < text.length && isIntersecting) {
                    const nextChar = text.charAt(currentIndex);
                    currentText += nextChar;
                    aiExplanationElement.innerText = currentText;
                    if (nextChar.match(/[，。！、？,.!?]/) || nextChar.match(/[a-zA-Z0-9]/)) {
                        aiExplanationElement.innerHTML = currentText + '<span class="blinking-cursor"></span>';
                    }
                    currentIndex++;
                    if (currentIndex < text.length) {
                        animationFrameId = requestAnimationFrame(render);
                    } else {
                        aiExplanationElement.innerHTML = text;
                        aiExplanationElement.style.display = "block";
                        this.scoGPTIsRunning = false;
                        aiTagElement.classList.remove("loadingAI");
                        observer.disconnect();
                        if (showSuggestions) {
                            this.createSuggestions();
                        }
                    }
                }
            };

            animationFrameId = requestAnimationFrame(render);
        }).catch((error) => {
            console.error("Failed to retrieve information:", error);
            aiExplanationElement.innerHTML = "检索信息失败";
            aiExplanationElement.style.display = "block";
            this.scoGPTIsRunning = false;
            aiTagElement.classList.remove("loadingAI");
            observer.disconnect();
        });
    }

    AIEngine() {
        const aiTagElement = document.querySelector(".ai-tag");
        if (aiTagElement) {
            aiTagElement.addEventListener("click", () => {
                if (!this.scoGPTIsRunning) {
                    this.aiTalkMode = true;
                    this.aiShowAnimation(Promise.resolve(this.config.talk), true);
                }
            });
        }
    }

    cleanSuggestions() {
        const suggestionsElement = document.querySelector(".ai-suggestions");
        if (suggestionsElement) {
            suggestionsElement.innerHTML = '';
        } else {
            console.error("没有这个元素：'ai-suggestions'");
        }
    }

    createSuggestions() {
        if (this.aiTalkMode) {
            this.cleanSuggestions();
            this.createSuggestionItemWithAction("这篇文章讲了什么？", () => {
                if (this.aiPostExplanation === '') {
                    this.generate();
                } else {
                    this.aiShowAnimation(Promise.resolve(this.aiPostExplanation), true);
                }
            });

            if (this.config.randomPost) {
                this.createSuggestionItemWithAction("带我去看看其他文章", toRandomPost);
            }

            this.aiTalkMode = true;
        }
    }

    createSuggestionItemWithAction(text, action) {
        const suggestionsElement = document.querySelector(".ai-suggestions");
        if (!suggestionsElement) {
            console.error("无法找到具有class为ai-suggestions的元素");
            return;
        }

        const item = document.createElement("div");
        item.classList.add("ai-suggestions-item");
        item.textContent = text;
        item.addEventListener("click", action);
        suggestionsElement.appendChild(item);
    }
}

const efu_ai = new efuAI();
